// ─── NOTION ───────────────────────────────────────────────────────────────────
const NOTION_DB_ID = "fb6f8473e9484de8a47839c7e0c34ddd";
const NOTION_BASE  = "/notion-proxy/v1";

const notionFetch = async (path, method="GET", body=null) => {
  const cfg = JSON.parse(localStorage.getItem("cs_cfg_v8")||"{}" );
  const token = cfg.notionToken || "";
  const opts = { method, headers:{"Content-Type":"application/json","X-Notion-Token":token} };
  if(body) opts.body = JSON.stringify(body);
  const r = await fetch(NOTION_BASE+path, opts);
  if(!r.ok){const e=await r.json().catch(()=>({}));throw new Error(e.message||`${r.status}`);}
  return r.json();
};

const notionToAcc = p => {
  const pr = p.properties, t=k=>pr[k]?.rich_text?.[0]?.plain_text??"", n=k=>pr[k]?.number??null;
  return { id:p.id, username:pr["Cuenta"]?.title?.[0]?.plain_text??"", displayName:t("Nombre Perfil"),
    followers:String(n("Seguidores")??""), link:pr["Link"]?.url??"", email:t("Email"),
    tikPass:t("Pass TikTok"), emailPass:t("Pass Email"), samePass:pr["Misma Contraseña"]?.checkbox??false,
    buyPrice:String(n("Precio Compra")??""), estSellPrice:String(n("Precio Venta Est.")??""),
    realSellPrice:n("Precio Venta Real"), profit:n("Ganancia"),
    status:pr["Estado"]?.select?.name??"available", country:t("País"),
    categories:t("Categorías").split(",").map(s=>s.trim()).filter(Boolean),
    niche:t("Nicho"), notes:t("Notas"), createdAt:p.created_time,
    soldAt:pr["Vendido El"]?.date?.start??null, disqAt:pr["Descalificado El"]?.date?.start??null, image:null };
};

const accToNotion = a => {
  const rt = v=>[{text:{content:String(v??"")}}];
  const props = {
    "Cuenta":           {title:[{text:{content:a.username||"sin usuario"}}]},
    "Nombre Perfil":    {rich_text:rt(a.displayName)}, "Seguidores":{number:parseFloat(a.followers)||0},
    "Link":             {url:a.link||null}, "Email":{rich_text:rt(a.email)},
    "Pass TikTok":      {rich_text:rt(a.tikPass)}, "Pass Email":{rich_text:rt(a.emailPass)},
    "Misma Contraseña": {checkbox:Boolean(a.samePass)},
    "Precio Compra":    {number:parseFloat(a.buyPrice)||0},
    "Precio Venta Est.":{number:parseFloat(a.estSellPrice)||0},
    "Precio Venta Real":{number:a.realSellPrice!=null?parseFloat(a.realSellPrice):null},
    "Ganancia":         {number:a.profit!=null?parseFloat(a.profit):null},
    "Estado":           {select:{name:a.status||"available"}}, "País":{rich_text:rt(a.country)},
    "Categorías":       {rich_text:rt((a.categories||[]).join(", "))},
    "Nicho":            {rich_text:rt(a.niche)}, "Notas":{rich_text:rt(a.notes)},
  };
  if(a.soldAt)  props["Vendido El"]       = {date:{start:a.soldAt.slice(0,10)}};
  if(a.disqAt)  props["Descalificado El"] = {date:{start:a.disqAt.slice(0,10)}};
  return props;
};

