// ─── UTILS ────────────────────────────────────────────────────────────────────
const fN  = n  => {const v=parseFloat(n)||0;return v>=1e6?(v/1e6).toFixed(1)+"M":v>=1e3?(v/1e3).toFixed(1)+"K":v.toLocaleString();};
const fD  = iso=> iso?new Date(iso).toLocaleDateString("es-VE",{day:"2-digit",month:"short",year:"numeric"}):"—";
const fU  = n  => "$"+(parseFloat(n)||0).toFixed(2);
const todayStr  = ()=>new Date().toISOString().slice(0,10);
const weekStart = ()=>{const d=new Date();d.setDate(d.getDate()-6);return d.toISOString().slice(0,10);};
const monthStr  = ()=>new Date().toISOString().slice(0,7);
const qStart    = ()=>{const d=new Date();return new Date(d.getFullYear(),Math.floor(d.getMonth()/3)*3,1).toISOString().slice(0,10);};
const inPeriod  = (iso,p)=>{if(!iso)return false;const d=iso.slice(0,10);return p==="today"?d===todayStr():p==="week"?d>=weekStart():p==="month"?d.startsWith(monthStr()):p==="quarter"?d>=qStart():true;};
const blankAcc  = ()=>({id:null,image:null,username:"",displayName:"",followers:"",link:"",email:"",tikPass:"",emailPass:"",samePass:false,buyPrice:"",estSellPrice:"",realSellPrice:null,status:"available",country:"",categories:[],niche:"",notes:"",createdAt:new Date().toISOString(),soldAt:null,disqAt:null,profit:null});
const lsGet     = k=>{try{const v=localStorage.getItem(k);return v?JSON.parse(v):null;}catch{return null;}};
const lsSet     = (k,v)=>{try{localStorage.setItem(k,JSON.stringify(v));}catch{}};

const clientFmt = a => {
  const sep = "━━━━━━━━━━━━━━━━━━━━━━";
  return [sep,"🎵  CUENTA TikTok PREMIUM  🎵",sep,"",
    `👤  @${a.username}`, `📊  ${fN(a.followers)} seguidores`,
    a.country?`🌎  ${a.country}`:null, a.niche?`✨  ${a.niche}`:null,"",
    sep,"🔐  DATOS DE ACCESO",sep,"",
    `📧  EMAIL        →  ${a.email}`, `🔑  PASS TikTok  →  ${a.tikPass}`,
    a.samePass?"🔄  Misma clave del email":`📬  PASS Email   →  ${a.emailPass}`,"",
    sep,"⚠️  IMPORTANTE",sep,
    "• No cambies la contraseña sin avisarme",
    "• No vincules número de teléfono", "• No reclames la cuenta",
    "• Cualquier duda, escríbeme 🤝","",sep,
    "🏪  Cimmaron.Shop — Stock de Cuentas TikTok",sep,
  ].filter(l=>l!==null).join("\n");
};

