// ─── AI HELPERS ───────────────────────────────────────────────────────────────
const analyzeImage = async (b64, mime, provider, key) => {
  const prompt = 'Analiza este perfil de TikTok. Responde SOLO JSON sin backticks:\n{"username":"","displayName":"","followers":0,"link":"","categories":[],"niche":""}\nCategorías disponibles: Creator Rare, TikTok Shop, Verificada, Monetizable, Alto Engagement, Vintage 3+, Monetizada.\nNiches: Moda, Gaming, Música, Entretenimiento, Comedia, Fitness, Tecnología, Gastronomía, Educación, Lifestyle, Negocios, Arte, Deportes, Belleza, Viajes. Usa null si no ves el dato.';
  if(provider==="anthropic"){
    const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":key},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:600,messages:[{role:"user",content:[{type:"image",source:{type:"base64",media_type:mime,data:b64}},{type:"text",text:prompt}]}]})});
    const d=await r.json();return JSON.parse((d.content?.find(c=>c.type==="text")?.text||"{}").replace(/```[\s\S]*?```/g,m=>m.slice(m.indexOf("\n")+1,-3)).trim());
  }
  if(provider==="openai"){
    const r=await fetch("https://api.openai.com/v1/chat/completions",{method:"POST",headers:{"Content-Type":"application/json","Authorization":`Bearer ${key}`},body:JSON.stringify({model:"gpt-4o",max_tokens:600,messages:[{role:"user",content:[{type:"image_url",image_url:{url:`data:${mime};base64,${b64}`}},{type:"text",text:prompt}]}]})});
    const d=await r.json();return JSON.parse((d.choices?.[0]?.message?.content||"{}").replace(/```[\s\S]*?```/g,m=>m.slice(m.indexOf("\n")+1,-3)).trim());
  }
  if(provider==="gemini"){
    const r=await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${key}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({contents:[{parts:[{inline_data:{mime_type:mime,data:b64}},{text:prompt}]}]})});
    const d=await r.json();return JSON.parse((d.candidates?.[0]?.content?.parts?.[0]?.text||"{}").replace(/```[\s\S]*?```/g,m=>m.slice(m.indexOf("\n")+1,-3)).trim());
  }
  throw new Error("Provider inválido");
};

