// ─── SMALL COMPONENTS ─────────────────────────────────────────────────────────
const SBadge = ({status}) => {
  const m = {available:["sb-av","Disponible","var(--cy)"], sold:["sb-so","Vendida","var(--a)"], disqualified:["sb-dq","Descalificada","var(--r)"]};
  const [c,l,col] = m[status]||m.available;
  return <span className={"sb "+c}><span className="sb-dot" style={{background:col}}/>{l}</span>;
};

const CredRow = ({label,val,hidden}) => {
  const [show,setShow] = useState(false), [cp,setCp] = useState(false);
  if(!val)return null;
  const copy=()=>navigator.clipboard?.writeText(val).then(()=>{setCp(true);setTimeout(()=>setCp(false),1500);});
  return <div className="cr">
    <span className="cl">{label}</span>
    <span className="cv">{hidden&&!show?"•••••••••":val}</span>
    {hidden&&<button className="cc" onClick={()=>setShow(s=>!s)}>{show?<I.eyex width={13} height={13}/>:<I.eye width={13} height={13}/>}</button>}
    <button className="cc" onClick={copy}>{cp?<I.chk width={13} height={13} style={{color:"var(--g)"}}/>:<I.copy width={13} height={13}/>}</button>
  </div>;
};

const AccRow = ({acc,onClick,delay=0}) => {
  const imgs=lsGet(SK_IMGS)||{}, img=acc.id?imgs[acc.id]:null;
  return <div className="arow fu" style={{animationDelay:delay+"s"}} onClick={onClick}>
    {img
      ? <img src={img} className="athumb" alt=""/>
      : <div className="ath-ph"><img src={LOGO_ICON} style={{width:26,height:26,objectFit:"contain",opacity:.4}} alt=""/></div>}
    <div className="ai">
      <div className="au">@{acc.username||"sin usuario"}</div>
      <div className="am">{fN(acc.followers)} · {acc.country||"—"} · {acc.niche||"—"}</div>
      <div style={{marginTop:5}}><SBadge status={acc.status}/></div>
    </div>
    <div className="apr">
      <div style={{fontFamily:"var(--fm)",fontWeight:700,fontSize:14,color:acc.status==="sold"?"var(--a)":"var(--t1)"}}>{fU(acc.estSellPrice)}</div>
      <div style={{fontSize:10,color:"var(--t2)",fontFamily:"var(--fm)",marginTop:1}}>costo {fU(acc.buyPrice)}</div>
      {acc.profit!=null&&<span className={"pp "+(acc.profit>=0?"pp-g":"pp-r")} style={{marginTop:4,display:"inline-flex"}}>{acc.profit>=0?"+":""}{fU(acc.profit)}</span>}
    </div>
  </div>;
};

// ─── MODALS ───────────────────────────────────────────────────────────────────
const SellModal = ({acc,onConfirm,onCancel}) => {
  const [p,setP]=useState(acc.estSellPrice||"");
  const pr=(parseFloat(p)||0)-(parseFloat(acc.buyPrice)||0);
  return <div className="ov" onClick={e=>e.target===e.currentTarget&&onCancel()}>
    <div className="sheet">
      <div className="sh"/>
      <div style={{fontFamily:"var(--fh)",fontSize:19,fontWeight:700,marginBottom:6}}>💰 Confirmar Venta</div>
      <div style={{fontSize:13,color:"var(--t2)",marginBottom:16}}>Precio real de venta para <span style={{fontWeight:700,color:"var(--t1)"}}>@{acc.username}</span></div>
      <div style={{padding:"12px 14px",background:"var(--s2)",border:"1.5px solid var(--bd)",borderRadius:"var(--r2)",marginBottom:14}}>
        <div style={{fontSize:10,color:"var(--t2)",fontWeight:700,letterSpacing:.5,textTransform:"uppercase",marginBottom:4}}>Precio estimado</div>
        <div style={{fontFamily:"var(--fm)",fontSize:22,fontWeight:700}}>{fU(acc.estSellPrice)}</div>
      </div>
      <div className="fg"><label className="fl">Precio real ($)</label>
        <input className="fin mono" type="number" step="0.01" placeholder={acc.estSellPrice||"0.00"} value={p} onChange={e=>setP(e.target.value)} autoFocus/>
      </div>
      {p&&<div className="mprev"><span style={{fontSize:13,color:"var(--t2)"}}>Ganancia neta</span><span style={{fontFamily:"var(--fm)",fontWeight:700,fontSize:16,color:pr>=0?"var(--cy)":"var(--r)"}}>{pr>=0?"+":""}{fU(pr)}</span></div>}
      <div style={{display:"flex",gap:8}}>
        <button className="bp" style={{flex:1}} onClick={()=>onConfirm(parseFloat(p)||parseFloat(acc.estSellPrice)||0)}>✓ Confirmar venta</button>
        <button className="bg" onClick={onCancel}>Cancelar</button>
      </div>
    </div>
  </div>;
};

const AccDetail = ({acc,countries,dark,onClose,onSell,onDisq,onRestore,onDelete,onEdit,onSoldToDisq}) => {
  const [cp,setCp]=useState(false),[del,setDel]=useState(false);
  const imgs=lsGet(SK_IMGS)||{}, img=acc.id?imgs[acc.id]:null;
  const ci=countries.find(c=>c.name===acc.country);
  const copyText=()=>navigator.clipboard?.writeText(clientFmt(acc)).then(()=>{setCp(true);setTimeout(()=>setCp(false),2500);});
  const shareWA=()=>shareViaWhatsApp(acc,img);
  return <div className="ov" onClick={e=>e.target===e.currentTarget&&onClose()}>
    <div className="sheet">
      <div className="sh"/>
      {img&&<img src={img} style={{width:"100%",maxHeight:150,objectFit:"cover",borderRadius:"var(--r2)",marginBottom:16}} alt=""/>}
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:14}}>
        <div>
          <div style={{fontFamily:"var(--fh)",fontSize:20,fontWeight:700}}>@{acc.username}</div>
          {acc.displayName&&<div style={{fontSize:13,color:"var(--t2)",marginTop:2}}>{acc.displayName}</div>}
          <div style={{marginTop:7}}><SBadge status={acc.status}/></div>
        </div>
        <div style={{display:"flex",gap:4}}>
          <button className="bi" onClick={onEdit}><I.edit width={15} height={15}/></button>
          <button className="bi" style={{color:"var(--r)"}} onClick={()=>setDel(true)}><I.trash width={15} height={15}/></button>
        </div>
      </div>
      <div className="card" style={{marginBottom:14}}>
        {[["Seguidores",fN(acc.followers)],["País",ci?ci.flag+" "+acc.country:acc.country||"—"],["Nicho",acc.niche||"—"],
          ["Compra",fU(acc.buyPrice),"mono"],["Venta Est.",fU(acc.estSellPrice),"mono"],
          acc.status==="sold"&&["Venta Real",fU(acc.realSellPrice),"mono","var(--a)"],
          acc.profit!=null&&["Ganancia",fU(acc.profit),"mono",acc.profit>=0?"var(--cy)":"var(--r)"],
          ["Registrado",fD(acc.createdAt)],acc.soldAt&&["Vendido",fD(acc.soldAt)],acc.disqAt&&["Descalificado",fD(acc.disqAt)]
        ].filter(Boolean).map(([l,v,t,c])=><div className="ir" key={l}>
          <span className="ir-l">{l}</span>
          <span className="ir-v" style={{fontFamily:t==="mono"?"var(--fm)":"inherit",color:c||"var(--t1)"}}>{v}</span>
        </div>)}
      </div>
      {acc.categories?.length>0&&<div className="chips" style={{marginBottom:14}}>
        {acc.categories.map(c=><span key={c} className="chip on" style={{cursor:"default",fontSize:11}}>{c}</span>)}
      </div>}
      {(acc.email||acc.tikPass)&&<>
        <div className="fl" style={{marginBottom:8}}>Credenciales</div>
        <div className="cb">
          <CredRow label="EMAIL" val={acc.email}/>
          <CredRow label="PASS TIKTOK" val={acc.tikPass} hidden/>
          {!acc.samePass&&<CredRow label="PASS EMAIL" val={acc.emailPass} hidden/>}
        </div>
      </>}
      {acc.notes&&<div style={{padding:"10px 13px",background:"var(--s2)",border:"1.5px solid var(--bd)",borderRadius:"var(--r2)",fontSize:13,color:"var(--t2)",marginBottom:14,lineHeight:1.6}}>{acc.notes}</div>}
      {acc.email&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
        <button onClick={copyText} style={{background:cp?"rgba(0,229,229,.1)":"var(--s2)",border:"1.5px solid "+(cp?"rgba(0,229,229,.35)":"var(--bd)"),color:cp?"var(--cy)":"var(--t2)",borderRadius:"var(--r2)",padding:"11px 8px",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"var(--ff)",display:"flex",alignItems:"center",justifyContent:"center",gap:6,transition:"all .25s"}}>
          {cp?<><I.chk width={13} height={13}/>¡Copiado!</>:<><I.copy width={13} height={13}/>Copiar texto</>}
        </button>
        <button onClick={shareWA} className="bwa">
          <I.wa width={14} height={14}/>Enviar por WA
        </button>
      </div>}
      {del
        ? <div className="sci" style={{padding:"14px",background:"var(--rb)",border:"1.5px solid rgba(255,59,92,.2)",borderRadius:"var(--r2)"}}>
            <div style={{fontSize:13,color:"var(--r)",fontWeight:600,marginBottom:12}}>¿Eliminar @{acc.username} permanentemente?</div>
            <div style={{display:"flex",gap:8}}><button className="bdn" style={{flex:1}} onClick={()=>{onDelete(acc.id);onClose();}}>Sí, eliminar</button><button className="bg" onClick={()=>setDel(false)}>Cancelar</button></div>
          </div>
        : <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            {acc.status==="available"&&<><button className="bp" style={{flex:1}} onClick={onSell}>💰 Vender</button><button className="bdn" style={{flexShrink:0}} onClick={()=>{onDisq(acc.id);onClose();}}>Descalif.</button></>}
            {acc.status==="sold"&&<><button className="bg" style={{flex:1}} onClick={onClose}>Cerrar</button><button className="bdn" style={{flexShrink:0}} onClick={()=>{onSoldToDisq(acc.id);onClose();}}>→ Descalif.</button></>}
            {acc.status==="disqualified"&&<button className="bg" style={{flex:1}} onClick={()=>{onRestore(acc.id);onClose();}}>↩ Restaurar</button>}
          </div>}
    </div>
  </div>;
};

// ─── SCREENS ──────────────────────────────────────────────────────────────────
const Dashboard = ({accounts,syncing,userInfo,dark,goto}) => {
  const av=accounts.filter(a=>a.status==="available").length,
        so=accounts.filter(a=>a.status==="sold").length,
        dq=accounts.filter(a=>a.status==="disqualified").length;
  const tP=accounts.filter(a=>a.status==="sold").reduce((s,a)=>s+(a.profit||0),0),
        tL=accounts.filter(a=>a.status==="disqualified").reduce((s,a)=>s+(parseFloat(a.buyPrice)||0),0),
        net=tP-tL;
  const todayP=accounts.filter(a=>a.status==="sold"&&a.soldAt?.slice(0,10)===todayStr()).reduce((s,a)=>s+(a.profit||0),0),
        monthP=accounts.filter(a=>a.status==="sold"&&a.soldAt?.startsWith(monthStr())).reduce((s,a)=>s+(a.profit||0),0),
        invVal=accounts.filter(a=>a.status==="available").reduce((s,a)=>s+(parseFloat(a.estSellPrice)||0),0);
  return <div className="screen">
    {syncing&&<div className="syncbar"><I.ref width={12} height={12} className="spin"/><span>Sincronizando con Notion...</span></div>}
    <div style={{padding:"52px 20px 0",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
      <div className="logo-pill">
        <img src={LOGO_ICON} style={{width:40,height:40,objectFit:"contain"}} alt="Cimaron"/>
      </div>
      <div style={{textAlign:"right"}}>
        <div style={{fontSize:10,color:"var(--t2)",fontWeight:600,letterSpacing:.4}}>
          {userInfo.loading?<span style={{animation:"shimmer 1.5s infinite"}}>Detectando...</span>
          :<span>{userInfo.flag} {userInfo.city||userInfo.country||"—"}</span>}
        </div>
        <div style={{fontFamily:"var(--fm)",fontSize:11,color:"var(--t3)"}}>{userInfo.ip||""}</div>
      </div>
    </div>
    <div style={{padding:"14px 20px 0"}}>
      <div style={{fontFamily:"var(--fh)",fontSize:13,fontWeight:700,color:"var(--cy)",letterSpacing:1,textTransform:"uppercase",marginBottom:2}}>Stock</div>
      <div style={{fontFamily:"var(--fh)",fontSize:28,fontWeight:700,letterSpacing:"-.5px"}}>Cuentas TikTok</div>
    </div>
    <div style={{padding:"16px 0"}}>
      <div className={"kpi-banner fu "+(net>=0?"pos":"neg")}>
        <div className="kpi-lbl">Flujo de Caja Neto</div>
        <div className="kpi-val" style={{color:net>=0?"var(--cy)":"var(--r)"}}>{net>=0?"+":""}{fU(net)}</div>
        <div className="kpi-sub">Ganancias {fU(tP)} · Pérdidas {fU(tL)}</div>
      </div>
    </div>
    <div className="sg">
      {[[av,"Disponibles","cy"],[so,"Vendidas","a"],[dq,"Descalificadas","r"],[accounts.length,"Total",""]].map(([v,l,c],i)=>(
        <div key={l} className={"sc fu "+c} style={{animationDelay:(i*.07)+"s"}}>
          <div className="sv">{v}</div><div className="sl">{l}</div>
        </div>
      ))}
    </div>
    <div className="sec">Ganancias</div>
    <div style={{padding:"0 20px"}}>
      <div className="card fu" style={{animationDelay:".18s"}}>
        {[["Hoy",todayP],["Este mes",monthP],["Total acumulado",tP],["En inventario",invVal,"var(--b)"]].map(([l,v,c])=>(
          <div className="ir" key={l}><span className="ir-l">{l}</span>
            <span className="ir-v" style={{fontFamily:"var(--fm)",color:c||(v>=0?"var(--cy)":"var(--r)")}}>{v>=0?"+":""}{fU(v)}</span>
          </div>
        ))}
      </div>
    </div>
    <div style={{padding:"14px 20px 0",display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
      <button className="bp fu" style={{animationDelay:".22s"}} onClick={()=>goto("add")}>+ Nueva Cuenta</button>
      <button className="bg fu" style={{animationDelay:".25s"}} onClick={()=>goto("inventory")}>Ver Stock</button>
    </div>
    {accounts.length>0&&<>
      <div className="sec">Últimas Cuentas</div>
      <div style={{margin:"0 20px",background:"var(--s1)",border:"1px solid var(--bd)",borderRadius:"var(--r1)",overflow:"hidden",boxShadow:"var(--sh2)"}}>
        {accounts.slice(0,3).map((a,i)=><AccRow key={a.id} acc={a} delay={i*.06} onClick={()=>goto("inventory")}/>)}
      </div>
    </>}
    {accounts.length===0&&!syncing&&<div className="empty fu" style={{marginTop:8}}>
      <div className="logo-pill" style={{marginBottom:8}}><img src={LOGO_ICON} style={{width:64,height:64,objectFit:"contain",opacity:.25}} alt=""/></div>
      <div style={{fontWeight:700,fontSize:17,fontFamily:"var(--fh)"}}>Sin cuentas aún</div>
      <div style={{color:"var(--t2)",fontSize:13}}>Empieza agregando tu primera cuenta TikTok</div>
      <button className="bp" style={{width:"auto",padding:"12px 24px",marginTop:6}} onClick={()=>goto("add")}>+ Agregar primera cuenta</button>
    </div>}
    <div style={{height:8}}/>
  </div>;
};

const Inventory = ({accounts,countries,syncing,onStatusChange,onDelete,onEdit,onSoldToDisq,dark}) => {
  const [sel,setSel]=useState(null),[sellAcc,setSellAcc]=useState(null);
  const [sf,setSf]=useState("all"),[cf,setCf]=useState(""),[catf,setCatf]=useState("");
  const usedC=[...new Set(accounts.map(a=>a.country).filter(Boolean))];
  const usedCat=[...new Set(accounts.flatMap(a=>a.categories||[]))];
  const list=accounts.filter(a=>(sf==="all"||a.status===sf)&&(!cf||a.country===cf)&&(!catf||a.categories?.includes(catf)));
  return <div className="screen">
    {syncing&&<div className="syncbar"><I.ref width={12} height={12} className="spin"/><span>Guardando...</span></div>}
    <div className="ph"><div className="ph-eyebrow">Inventario</div><div className="ph-title">Stock de Cuentas</div><div className="ph-sub">{list.length} cuenta{list.length!==1?"s":""} mostradas</div></div>
    <div className="frow">
      {[["all","Todas"],["available","Disponibles"],["sold","Vendidas"],["disqualified","Descalificadas"]].map(([v,l])=>(
        <button key={v} className={"fc "+(sf===v?"on":"")} onClick={()=>setSf(v)}>{l}</button>
      ))}
      {usedC.map(c=>{const ci=countries.find(x=>x.name===c);return <button key={c} className={"fc "+(cf===c?"on":"")} onClick={()=>setCf(cf===c?"":c)}>{ci?.flag||"🌎"} {c}</button>;})}
      {usedCat.map(c=><button key={c} className={"fc "+(catf===c?"on":"")} onClick={()=>setCatf(catf===c?"":c)}>{c}</button>)}
    </div>
    {list.length===0
      ? <div className="empty"><div style={{fontSize:36,opacity:.15}}>📋</div><div style={{color:"var(--t2)",fontWeight:500}}>Sin cuentas con estos filtros</div></div>
      : <div style={{margin:"0 20px",background:"var(--s1)",border:"1px solid var(--bd)",borderRadius:"var(--r1)",overflow:"hidden",boxShadow:"var(--sh2)"}}>
          {list.map((a,i)=><AccRow key={a.id} acc={a} delay={i*.04} onClick={()=>setSel(a)}/>)}
        </div>}
    {sel&&!sellAcc&&<AccDetail acc={sel} countries={countries} dark={dark} onClose={()=>setSel(null)} onSell={()=>{setSellAcc(sel);setSel(null);}} onDisq={id=>{onStatusChange(id,"disqualified");setSel(null);}} onRestore={id=>{onStatusChange(id,"available");setSel(null);}} onDelete={id=>{onDelete(id);setSel(null);}} onEdit={()=>{onEdit(sel);setSel(null);}} onSoldToDisq={id=>{onSoldToDisq(id);setSel(null);}}/>}
    {sellAcc&&<SellModal acc={sellAcc} onConfirm={rp=>{onStatusChange(sellAcc.id,"sold",rp);setSellAcc(null);}} onCancel={()=>setSellAcc(null)}/>}
  </div>;
};

const AddEdit = ({onSave,onCancel,countries,cats,editAcc,syncing,aiProviders,activeAIId}) => {
  const isEdit=!!editAcc;
  const [step,setStep]=useState(isEdit?2:1);
  const [form,setForm]=useState(isEdit?{...editAcc}:blankAcc());
  const [analyzing,setAnalyzing]=useState(false),[done,setDone]=useState(false);
  const fileRef=useRef();

  useEffect(()=>{if(isEdit){setForm({...editAcc});setStep(2);}},[editAcc?.id]);
  const set=(k,v)=>setForm(p=>({...p,[k]:v}));
  const togCat=c=>set("categories",form.categories.includes(c)?form.categories.filter(x=>x!==c):[...form.categories,c]);

  const handleImg=async e=>{
    const file=e.target.files[0];if(!file)return;
    const reader=new FileReader();
    reader.onload=async ev=>{
      const dataUrl=ev.target.result;
      setForm(p=>({...p,image:dataUrl}));setAnalyzing(true);
      const prov=aiProviders.find(p=>p.id===activeAIId);
      try{
        const b64=dataUrl.split(",")[1];
        const parsed=await analyzeImage(b64,file.type,prov?.id||"anthropic",prov?.key||"");
        setForm(p=>({...p,image:dataUrl,
          username:   parsed.username    ||p.username,
          displayName:parsed.displayName ||p.displayName,
          followers:  parsed.followers   ?String(parsed.followers):p.followers,
          link:       parsed.link        ||p.link,
          categories: parsed.categories?.length?parsed.categories.filter(c=>cats.includes(c)):p.categories,
          niche:      parsed.niche       ||p.niche,
        }));
      }catch(err){console.error("AI analyze:",err);}
      finally{setAnalyzing(false);setStep(2);}
    };
    reader.readAsDataURL(file);
  };

  const save=()=>{onSave(form);setDone(true);setTimeout(()=>{setDone(false);setForm(blankAcc());setStep(1);},2000);};
  const profit=(parseFloat(form.estSellPrice||0))-(parseFloat(form.buyPrice||0));
  const activeProv=aiProviders.find(p=>p.id===activeAIId);

  if(done)return <div className="screen" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"80dvh",gap:16}}>
    <div style={{fontSize:40,animation:"popIn .5s ease"}}>✅</div>
    <div style={{fontFamily:"var(--fh)",fontWeight:700,fontSize:18,color:"var(--cy)"}}>{isEdit?"¡Cambios guardados!":"¡Cuenta agregada!"}</div>
    <div style={{fontSize:13,color:"var(--t2)"}}>Sincronizando con Notion...</div>
  </div>;

  return <div className="screen">
    {syncing&&<div className="syncbar"><I.ref width={12} height={12} className="spin"/><span>Guardando en Notion...</span></div>}
    <div className="ph">
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div>
          <div className="ph-eyebrow">{isEdit?"Editar":"Nueva Cuenta"}</div>
          <div className="ph-title">{isEdit?"@"+form.username:"Agregar Cuenta"}</div>
          {!isEdit&&activeProv?.key&&<div style={{fontSize:11,color:"var(--cy)",marginTop:4}}>🤖 IA: {AI_PROVIDERS.find(p=>p.id===activeAIId)?.name}</div>}
        </div>
        {isEdit&&<button className="bi" onClick={onCancel}><I.x width={18} height={18}/></button>}
      </div>
    </div>
    {!isEdit&&<div className="stps">{[1,2,3].map(n=><div key={n} className={"stp "+(step>n?"dn":step===n?"cur":"")}/>)}</div>}
    <div style={{padding:"0 20px"}}>

      {/* STEP 1 */}
      {step===1&&!isEdit&&<div className="fu">
        <div style={{fontSize:10,color:"var(--cy)",fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:4}}>Paso 1 de 3</div>
        <div style={{fontFamily:"var(--fh)",fontSize:20,fontWeight:700,marginBottom:16}}>Sube la captura</div>
        <div className="fg"><div className="iu" onClick={()=>fileRef.current.click()}>
          {form.image&&<img src={form.image} alt=""/>}
          {!form.image&&<div style={{textAlign:"center",padding:"0 20px"}}>
            <I.cam width={28} height={28} style={{color:"var(--t3)",marginBottom:8}}/>
            <div style={{fontSize:13,color:"var(--t2)",lineHeight:1.6}}>Toca para subir captura de pantalla</div>
            {activeProv?.key&&<div style={{fontSize:11,color:"var(--cy)",marginTop:6,fontWeight:600}}>✨ La IA detectará datos y categorías</div>}
          </div>}
          <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleImg}/>
        </div></div>
        {analyzing&&<div className="ana"><I.spark width={14} height={14} className="spin"/><span>Analizando con IA — detectando categorías, nicho y datos...</span></div>}
        {!analyzing&&<button className="bp" onClick={()=>setStep(2)}>{form.image?"Continuar →":"Saltar imagen →"}</button>}
      </div>}

      {/* STEP 2 */}
      {(step===2||isEdit)&&<div className={isEdit?"":"fu"}>
        {!isEdit&&<><div style={{fontSize:10,color:"var(--cy)",fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:4}}>Paso 2 de 3</div>
          <div style={{fontFamily:"var(--fh)",fontSize:20,fontWeight:700,marginBottom:16}}>Confirma los datos</div></>}
        {isEdit&&<div className="fg"><label className="fl">Imagen</label>
          <div className="iu" style={{height:110}} onClick={()=>fileRef.current.click()}>
            {form.image&&<img src={form.image} alt=""/>}
            {!form.image&&<I.cam width={22} height={22} style={{color:"var(--t3)"}}/>}
            <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleImg}/>
          </div></div>}
        <div className="g2">
          <div className="fg"><label className="fl">Usuario (sin @)</label><input className="fin" placeholder="username" value={form.username} onChange={e=>set("username",e.target.value.replace("@",""))}/></div>
          <div className="fg"><label className="fl">Nombre perfil</label><input className="fin" placeholder="Nombre TikTok" value={form.displayName} onChange={e=>set("displayName",e.target.value)}/></div>
        </div>
        <div className="g2">
          <div className="fg"><label className="fl">Seguidores</label><input className="fin mono" type="number" placeholder="50000" value={form.followers} onChange={e=>set("followers",e.target.value)}/></div>
          <div className="fg"><label className="fl">País</label><select className="fin" value={form.country} onChange={e=>set("country",e.target.value)}><option value="">Seleccionar...</option>{countries.map(c=><option key={c.code} value={c.name}>{c.flag} {c.name}</option>)}</select></div>
        </div>
        <div className="fg"><label className="fl">Nicho</label><select className="fin" value={form.niche} onChange={e=>set("niche",e.target.value)}><option value="">Seleccionar...</option>{NICHES.map(n=><option key={n}>{n}</option>)}</select></div>
        <div className="fg"><label className="fl">Link TikTok</label><input className="fin mono" placeholder="https://tiktok.com/@..." value={form.link} onChange={e=>set("link",e.target.value)}/></div>
        <div className="fg">
          <label className="fl">Características {form.categories.length>0&&<span style={{color:"var(--cy)",fontWeight:400,textTransform:"none"}}>· {form.categories.length} seleccionadas</span>}</label>
          <div className="chips">{cats.map(c=><button key={c} className={"chip "+(form.categories.includes(c)?"on":"")} onClick={()=>togCat(c)}>{c}</button>)}</div>
        </div>
        <div className="g2">
          <div className="fg"><label className="fl">Precio Compra $</label><input className="fin mono" type="number" step="0.01" placeholder="0.00" value={form.buyPrice} onChange={e=>set("buyPrice",e.target.value)}/></div>
          <div className="fg"><label className="fl">Precio Venta Est. $</label><input className="fin mono" type="number" step="0.01" placeholder="0.00" value={form.estSellPrice} onChange={e=>set("estSellPrice",e.target.value)}/></div>
        </div>
        {form.buyPrice&&form.estSellPrice&&<div className="mprev">
          <span style={{fontSize:13,color:"var(--t2)"}}>Margen estimado</span>
          <span style={{fontFamily:"var(--fm)",fontWeight:700,color:profit>=0?"var(--cy)":"var(--r)",fontSize:16}}>{profit>=0?"+":""}{fU(profit)}</span>
        </div>}
        <div className="fg"><label className="fl">Notas</label><textarea className="fin" rows={2} placeholder="Observaciones internas..." value={form.notes} onChange={e=>set("notes",e.target.value)}/></div>
        {!isEdit&&<><button className="bp" onClick={()=>setStep(3)} disabled={!form.username.trim()} style={{marginBottom:8}}>Continuar →</button>
          <button className="bg" style={{width:"100%",marginBottom:16}} onClick={()=>setStep(1)}>← Atrás</button></>}
      </div>}

      {/* STEP 3 */}
      {(step===3||isEdit)&&<div className={isEdit?"":"fu"}>
        {!isEdit&&<><div style={{fontSize:10,color:"var(--cy)",fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:4,marginTop:8}}>Paso 3 de 3</div>
          <div style={{fontFamily:"var(--fh)",fontSize:20,fontWeight:700,marginBottom:16}}>Credenciales de acceso</div></>}
        <div className="fg"><label className="fl">Email de la cuenta</label><input className="fin mono" type="email" placeholder="cuenta@email.com" value={form.email} onChange={e=>set("email",e.target.value)}/></div>
        <div className="fg"><label className="fl">Contraseña TikTok</label><input className="fin mono" placeholder="Contraseña TikTok" value={form.tikPass} onChange={e=>{set("tikPass",e.target.value);if(form.samePass)set("emailPass",e.target.value);}}/></div>
        <div className="trow" onClick={()=>{const v=!form.samePass;set("samePass",v);if(v)set("emailPass",form.tikPass);}}>
          <span style={{fontSize:13,cursor:"pointer"}}>Contraseña email = contraseña TikTok</span>
          <label className="tog" onClick={e=>e.stopPropagation()}><input type="checkbox" checked={form.samePass} onChange={e=>{set("samePass",e.target.checked);if(e.target.checked)set("emailPass",form.tikPass);}}/><span className="tsl"/></label>
        </div>
        {!form.samePass&&<div className="fg"><label className="fl">Contraseña Email</label><input className="fin mono" placeholder="Contraseña del email" value={form.emailPass} onChange={e=>set("emailPass",e.target.value)}/></div>}
        {form.email&&<div className="fg"><label className="fl">Vista previa del formato</label><div className="cpb">{clientFmt(form)}</div></div>}
        <button className="bp" onClick={save} disabled={!form.username.trim()||syncing} style={{marginBottom:8}}>
          {isEdit?"✓ Guardar cambios":"✓ Guardar en Notion"}
        </button>
        {!isEdit&&<button className="bg" style={{width:"100%",marginBottom:16}} onClick={()=>setStep(2)}>← Atrás</button>}
      </div>}
    </div>
  </div>;
};

const Reportes = ({accounts}) => {
  const [period,setPeriod]=useState("month");
  const fS=accounts.filter(a=>a.status==="sold"&&inPeriod(a.soldAt,period));
  const fD=accounts.filter(a=>a.status==="disqualified"&&inPeriod(a.disqAt||a.createdAt,period));
  const tP=fS.reduce((s,a)=>s+(a.profit||0),0),tL=fD.reduce((s,a)=>s+(parseFloat(a.buyPrice)||0),0);
  const tR=fS.reduce((s,a)=>s+(parseFloat(a.realSellPrice)||0),0),tC=fS.reduce((s,a)=>s+(parseFloat(a.buyPrice)||0),0);
  const net=tP-tL,margin=tR>0?(tP/tR)*100:0,avg=fS.length>0?tP/fS.length:0;
  const byDay={};fS.forEach(a=>{const d=a.soldAt?.slice(0,10);if(d)byDay[d]=(byDay[d]||0)+(a.profit||0);});
  const bars=Object.entries(byDay).sort().slice(-14),maxBar=Math.max(...bars.map(([,v])=>v),1);
  return <div className="screen">
    <div className="ph"><div className="ph-eyebrow">Estadísticas</div><div className="ph-title">Reportes</div><div className="ph-sub">{fS.length} venta{fS.length!==1?"s":""} · {fD.length} pérdida{fD.length!==1?"s":""}</div></div>
    <div className="rp">{[["today","Hoy"],["week","Semana"],["month","Mes"],["quarter","Trimestre"],["all","Todo"]].map(([v,l])=><button key={v} className={"rpb "+(period===v?"on":"")} onClick={()=>setPeriod(v)}>{l}</button>)}</div>
    <div style={{padding:"0 20px"}}>
      <div className={"kpi-banner fu "+(net>=0?"pos":"neg")} style={{marginBottom:14,marginLeft:0,marginRight:0}}>
        <div className="kpi-lbl">Ganancia Neta del Período</div>
        <div className="kpi-val" style={{color:net>=0?"var(--cy)":"var(--r)"}}>{net>=0?"+":""}{fU(net)}</div>
        <div className="kpi-sub">{fS.length} vendidas · {fD.length} descalificadas</div>
      </div>
      <div className="sg" style={{padding:0,marginBottom:12}}>
        {[["Ingresos",fU(tR),""],["Costos",fU(tC),"r"],["Ganancias",fU(tP),"cy"],["Pérdidas",fU(tL),"r"],["Promedio",fU(avg),"cy"],["Margen",margin.toFixed(1)+"%","b"]].map(([l,v,c],i)=>(
          <div key={l} className={"sc fu "+c} style={{animationDelay:(i*.05)+"s"}}><div className="sv" style={{fontSize:16}}>{v}</div><div className="sl">{l}</div></div>
        ))}
      </div>
      {bars.length>1&&<div className="card fu" style={{marginBottom:12,animationDelay:".15s"}}>
        <div style={{fontSize:10,color:"var(--t2)",fontWeight:700,letterSpacing:.6,textTransform:"uppercase",marginBottom:12}}>Ganancias por día</div>
        <div className="bars">{bars.map(([d,v])=><div key={d} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-end",height:"100%"}}>
          <div style={{height:Math.max(4,(v/maxBar)*100)+"%",background:v>=0?"var(--cy)":"var(--r)",opacity:.85,width:"100%",borderRadius:"4px 4px 0 0",transition:"height .35s"}}/>
        </div>)}</div>
        <div style={{display:"flex",justifyContent:"space-between",marginTop:6}}><span style={{fontSize:10,color:"var(--t3)"}}>{bars[0]?.[0]?.slice(5)}</span><span style={{fontSize:10,color:"var(--t3)"}}>{bars[bars.length-1]?.[0]?.slice(5)}</span></div>
      </div>}
      {fS.length>0&&<div className="card fu" style={{padding:0,overflow:"hidden",marginBottom:12,animationDelay:".2s"}}>
        <div style={{padding:"12px 16px",borderBottom:"1px solid var(--bd2)",fontSize:10,color:"var(--t2)",fontWeight:700,letterSpacing:.6,textTransform:"uppercase"}}>Detalle de ventas</div>
        {fS.map(a=><div key={a.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 16px",borderBottom:"1px solid var(--bd2)"}}>
          <div><div style={{fontSize:13,fontWeight:600}}>@{a.username}</div><div style={{fontSize:11,color:"var(--t2)"}}>{fD(a.soldAt)}</div></div>
          <div style={{textAlign:"right"}}><div style={{fontFamily:"var(--fm)",fontWeight:700,fontSize:13,color:"var(--a)"}}>{fU(a.realSellPrice)}</div>
            <span className={"pp "+((a.profit||0)>=0?"pp-g":"pp-r")}>{(a.profit||0)>=0?"+":""}{fU(a.profit)}</span></div>
        </div>)}
      </div>}
      {fD.length>0&&<div className="card fu" style={{padding:0,overflow:"hidden",marginBottom:12,animationDelay:".25s"}}>
        <div style={{padding:"12px 16px",borderBottom:"1px solid var(--bd2)",fontSize:10,color:"var(--r)",fontWeight:700,letterSpacing:.6,textTransform:"uppercase"}}>Pérdidas</div>
        {fD.map(a=><div key={a.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 16px",borderBottom:"1px solid var(--bd2)"}}>
          <div><div style={{fontSize:13,fontWeight:600}}>@{a.username}</div><div style={{fontSize:11,color:"var(--t2)"}}>{fD(a.disqAt||a.createdAt)}</div></div>
          <span className="pp pp-r">-{fU(a.buyPrice)}</span>
        </div>)}
      </div>}
      {fS.length===0&&fD.length===0&&<div className="empty"><div style={{fontSize:36,opacity:.15}}>📊</div><div style={{color:"var(--t2)",fontWeight:500}}>Sin movimientos en este período</div></div>}
    </div>
  </div>;
};

const Buscar = ({accounts,countries,dark,onStatusChange,onDelete,onEdit,onSoldToDisq}) => {
  const [q,setQ]=useState(""),[sf,setSf]=useState("all"),[cf,setCf]=useState("");
  const [sel,setSel]=useState(null),[sellAcc,setSellAcc]=useState(null);
  const list=accounts.filter(a=>{const lq=q.toLowerCase();const t=!q||[a.username,a.displayName,a.niche,a.email,a.notes,a.country].some(v=>v?.toLowerCase().includes(lq));return t&&(sf==="all"||a.status===sf)&&(!cf||a.country===cf);});
  return <div className="screen">
    <div className="ph"><div className="ph-eyebrow">Buscar</div><div className="ph-title">Explorar Stock</div></div>
    <div className="sbar" style={{marginBottom:10}}><I.srch width={15} height={15} style={{color:"var(--t2)",flexShrink:0}}/><input placeholder="Usuario, email, nicho, país..." value={q} onChange={e=>setQ(e.target.value)} autoFocus/>{q&&<button className="bi" onClick={()=>setQ("")} style={{padding:4}}><I.x width={13} height={13}/></button>}</div>
    <div className="frow">{[["all","Todas"],["available","Disponibles"],["sold","Vendidas"],["disqualified","Descalif."]].map(([v,l])=><button key={v} className={"fc "+(sf===v?"on":"")} onClick={()=>setSf(v)}>{l}</button>)}{[...new Set(accounts.map(a=>a.country).filter(Boolean))].map(c=>{const ci=countries.find(x=>x.name===c);return <button key={c} className={"fc "+(cf===c?"on":"")} onClick={()=>setCf(cf===c?"":c)}>{ci?.flag||"🌎"} {c}</button>;})}</div>
    {(q||cf||sf!=="all")&&<div style={{padding:"0 20px 8px",fontSize:12,color:"var(--t2)",fontWeight:500}}>{list.length} resultado{list.length!==1?"s":""}</div>}
    {list.length>0
      ? <div style={{margin:"0 20px",background:"var(--s1)",border:"1px solid var(--bd)",borderRadius:"var(--r1)",overflow:"hidden",boxShadow:"var(--sh2)"}}>
          {list.map((a,i)=><AccRow key={a.id} acc={a} delay={i*.04} onClick={()=>setSel(a)}/>)}
        </div>
      : <div className="empty"><div style={{fontSize:36,opacity:.15}}>🔍</div><div style={{color:"var(--t2)",fontWeight:500}}>{q||cf?"Sin resultados":"Escribe para buscar"}</div></div>}
    {sel&&!sellAcc&&<AccDetail acc={sel} countries={countries} dark={dark} onClose={()=>setSel(null)} onSell={()=>{setSellAcc(sel);setSel(null);}} onDisq={id=>{onStatusChange(id,"disqualified");setSel(null);}} onRestore={id=>{onStatusChange(id,"available");setSel(null);}} onDelete={id=>{onDelete(id);setSel(null);}} onEdit={()=>{onEdit(sel);setSel(null);}} onSoldToDisq={id=>{onSoldToDisq(id);setSel(null);}}/>}
    {sellAcc&&<SellModal acc={sellAcc} onConfirm={rp=>{onStatusChange(sellAcc.id,"sold",rp);setSellAcc(null);}} onCancel={()=>setSellAcc(null)}/>}
  </div>;
};

const NotionTokenInput = ({notionOk}) => {
  const cfg = JSON.parse(localStorage.getItem("cs_cfg_v8")||"{}" );
  const [tok, setTok] = useState(cfg.notionToken||"");
  const [saved, setSaved] = useState(false);

  const save = () => {
    const c = JSON.parse(localStorage.getItem("cs_cfg_v8")||"{}" );
    c.notionToken = tok.trim();
    localStorage.setItem("cs_cfg_v8", JSON.stringify(c));
    setSaved(true);
    setTimeout(()=>setSaved(false), 2000);
    window.location.reload();
  };

  return <div style={{display:"flex",gap:8,alignItems:"center"}}>
    <input
      className="fin mono"
      type="password"
      placeholder="ntn_... o secret_..."
      value={tok}
      onChange={e=>{setTok(e.target.value);setSaved(false);}}
      style={{flex:1,fontSize:12}}
    />
    <button className="bp" style={{width:"auto",padding:"11px 14px",flexShrink:0}} onClick={save}>
      {saved ? "✓" : "Guardar"}
    </button>
  </div>;
};

const Ajustes = ({dark,setDark,countries,setCountries,cats,setCats,notionOk,aiProviders,setAiProviders,activeAIId,setActiveAIId}) => {
  const [nc,setNc]=useState({flag:"",name:""}), [ncat,setNcat]=useState("");
  const [editProv,setEditProv]=useState(null);
  const [apiStatus,setApiStatus]=useState({});

  const testProvider=async(id,key)=>{
    setApiStatus(s=>({...s,[id]:"checking"}));
    const ok=await testKey(id,key);
    setApiStatus(s=>({...s,[id]:ok?"ok":"err"}));
    if(ok) setAiProviders(prev=>prev.map(p=>p.id===id?{...p,key}:p));
  };
  const activeP=aiProviders.find(p=>p.id===activeAIId);

  return <div className="screen">
    <div className="ph"><div className="ph-eyebrow">App</div><div className="ph-title">Configuración</div></div>
    <div style={{padding:"0 20px"}}>

      {/* Notion */}
      <div style={{fontWeight:700,fontSize:10,color:"var(--t2)",letterSpacing:.8,textTransform:"uppercase",marginBottom:10}}>Notion</div>
      <div className="card fu" style={{marginBottom:10,borderColor:notionOk?"rgba(0,229,229,.3)":"rgba(255,59,92,.25)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
          <span className={"ndot"+(notionOk?"":" off")}/>
          <div><div style={{fontWeight:700,fontSize:14}}>Notion {notionOk?"✓ Conectado":"Desconectado"}</div>
            <div style={{fontSize:12,color:"var(--t2)",marginTop:2}}>{notionOk?"Base de datos sincronizada":"Ingresa tu token de integración"}</div></div>
        </div>
        <label className="fl">Token de integración</label>
        <NotionTokenInput notionOk={notionOk}/>
      </div>

      {/* IA */}
      <div style={{fontWeight:700,fontSize:10,color:"var(--t2)",letterSpacing:.8,textTransform:"uppercase",marginBottom:10}}>Inteligencia Artificial</div>
      <div className="card fu" style={{marginBottom:10}}>
        <label className="fl">IA activa para análisis</label>
        <select className="fin" value={activeAIId} onChange={e=>setActiveAIId(e.target.value)}>
          {aiProviders.filter(p=>p.key).map(p=><option key={p.id} value={p.id}>{AI_PROVIDERS.find(x=>x.id===p.id)?.icon} {AI_PROVIDERS.find(x=>x.id===p.id)?.name}</option>)}
          {aiProviders.filter(p=>p.key).length===0&&<option value="">— Configura una API primero —</option>}
        </select>
        {activeP?.key&&<div style={{fontSize:12,color:"var(--cy)",marginTop:7,fontWeight:600}}>✓ Activo: {AI_PROVIDERS.find(p=>p.id===activeAIId)?.name}</div>}
      </div>
      {AI_PROVIDERS.map((prov,i)=>{
        const saved=aiProviders.find(p=>p.id===prov.id);
        const st=apiStatus[prov.id], isEditing=editProv?.provider===prov.id;
        return <div key={prov.id} className="card fu" style={{marginBottom:10,animationDelay:(.06+i*.04)+"s"}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:isEditing?12:0}}>
            <div><div style={{fontWeight:700,fontSize:14}}>{prov.icon} {prov.name}</div>
              <div style={{fontSize:11,marginTop:2,color:saved?.key?"var(--g)":"var(--t3)",fontWeight:500}}>{saved?.key?"✓ API configurada":"Sin configurar"}</div></div>
            <button className="bg" style={{padding:"7px 13px",fontSize:12}} onClick={()=>setEditProv(isEditing?null:{provider:prov.id,key:saved?.key||""})}>{isEditing?"Cerrar":"Configurar"}</button>
          </div>
          {isEditing&&<>
            <div style={{display:"flex",gap:8,alignItems:"center"}}>
              <input className="fin mono" type="password" placeholder={prov.placeholder} value={editProv.key} onChange={e=>setEditProv(p=>({...p,key:e.target.value}))} style={{flex:1}}/>
              <button className="bp" style={{width:"auto",padding:"11px 14px",flexShrink:0}} onClick={()=>testProvider(prov.id,editProv.key)} disabled={st==="checking"}>
                {st==="checking"?<I.ref width={14} height={14} className="spin"/>:"Probar"}
              </button>
            </div>
            {st==="ok"&&<div className="ast-ok"><I.chk width={13} height={13}/>API válida — guardada</div>}
            {st==="err"&&<div className="ast-err"><I.x width={13} height={13}/>API inválida o sin permisos</div>}
          </>}
        </div>;
      })}

      {/* Tema */}
      <div style={{fontWeight:700,fontSize:10,color:"var(--t2)",letterSpacing:.8,textTransform:"uppercase",marginBottom:10,marginTop:6}}>Apariencia</div>
      <div className="card fu" style={{marginBottom:16}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            {dark?<I.moon width={16} height={16} style={{color:"var(--b)"}}/>:<I.sun width={16} height={16} style={{color:"var(--a)"}}/>}
            <div><div style={{fontWeight:600,fontSize:14}}>Modo {dark?"Oscuro":"Claro"}</div>
              <div style={{fontSize:12,color:"var(--t2)"}}>Tema de la interfaz</div></div>
          </div>
          <label className="tog"><input type="checkbox" checked={dark} onChange={e=>setDark(e.target.checked)}/><span className="tsl"/></label>
        </div>
      </div>

      {/* Países */}
      <div style={{fontWeight:700,fontSize:10,color:"var(--t2)",letterSpacing:.8,textTransform:"uppercase",marginBottom:10}}>Países</div>
      <div className="card fu" style={{marginBottom:10,padding:0,overflow:"hidden"}}>
        {countries.map((c,i)=><div key={i} style={{display:"flex",alignItems:"center",padding:"10px 14px",borderBottom:"1px solid var(--bd2)",gap:10}}>
          <span style={{fontSize:18}}>{c.flag}</span>
          <span style={{flex:1,fontSize:13,fontWeight:500}}>{c.name}</span>
          <button className="bi" style={{color:"var(--r)"}} onClick={()=>setCountries(p=>p.filter((_,j)=>j!==i))}><I.trash width={13} height={13}/></button>
        </div>)}
      </div>
      <div style={{display:"flex",gap:8,marginBottom:20}}>
        <input className="fin" style={{width:56}} placeholder="🌍" value={nc.flag} onChange={e=>setNc(p=>({...p,flag:e.target.value}))}/>
        <input className="fin" placeholder="Nombre del país" value={nc.name} onChange={e=>setNc(p=>({...p,name:e.target.value}))} style={{flex:1}} onKeyDown={e=>e.key==="Enter"&&nc.name.trim()&&(setCountries(p=>[...p,{code:nc.name.slice(0,2).toUpperCase(),name:nc.name.trim(),flag:nc.flag||"🌎"}]),setNc({flag:"",name:""}))}/>
        <button className="bp" style={{width:"auto",padding:"0 18px",flexShrink:0}} onClick={()=>{if(!nc.name.trim())return;setCountries(p=>[...p,{code:nc.name.slice(0,2).toUpperCase(),name:nc.name.trim(),flag:nc.flag||"🌎"}]);setNc({flag:"",name:""});}}>+</button>
      </div>

      {/* Categorías */}
      <div style={{fontWeight:700,fontSize:10,color:"var(--t2)",letterSpacing:.8,textTransform:"uppercase",marginBottom:10}}>Categorías</div>
      <div className="fu" style={{marginBottom:10}}>
        <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
          {cats.map((c,i)=><span key={i} style={{display:"inline-flex",alignItems:"center",gap:4,padding:"6px 10px 6px 12px",borderRadius:20,fontSize:12,fontWeight:600,background:"rgba(0,229,229,.1)",border:"1.5px solid rgba(0,229,229,.3)",color:"var(--cy)"}}>
            {c}<button style={{background:"none",border:"none",cursor:"pointer",color:"var(--cy)",padding:"0 0 0 2px",display:"flex",alignItems:"center",opacity:.7}} onClick={()=>setCats(p=>p.filter((_,j)=>j!==i))}><I.x width={11} height={11}/></button>
          </span>)}
        </div>
      </div>
      <div style={{display:"flex",gap:8,marginBottom:24}}>
        <input className="fin" placeholder="Nueva categoría..." value={ncat} onChange={e=>setNcat(e.target.value)} style={{flex:1}} onKeyDown={e=>e.key==="Enter"&&(ncat.trim()&&!cats.includes(ncat.trim())&&(setCats(p=>[...p,ncat.trim()]),setNcat("")))}/>
        <button className="bp" style={{width:"auto",padding:"0 18px",flexShrink:0}} onClick={()=>{if(!ncat.trim()||cats.includes(ncat.trim()))return;setCats(p=>[...p,ncat.trim()]);setNcat("");}}>+</button>
      </div>

      {/* About */}
      <div style={{background:"var(--s2)",border:"1px solid var(--bd)",borderRadius:"var(--r1)",padding:20,textAlign:"center",marginBottom:20}}>
        <div style={{background:"#0A0A0A",borderRadius:12,padding:"12px 16px",display:"inline-block",marginBottom:12}}>
          <img src={LOGO_VERT} style={{width:160,height:"auto",objectFit:"contain"}} alt="Cimaron"/>
        </div>
        <div style={{fontSize:11,color:"var(--t2)"}}>Stock de Cuentas TikTok</div>
        <div style={{fontSize:11,color:"var(--t3)",marginTop:3}}>Powered by <a href="https://cimmaron.shop" target="_blank" style={{color:"var(--cy)",textDecoration:"none",fontWeight:700}}>Cimmaron.Shop</a></div>
      </div>
    </div>
  </div>;
};

// ─── APP ROOT ─────────────────────────────────────────────────────────────────
export default function App() {
  const [dark,setDark]           = useState(true);
  const [view,setView]           = useState("dashboard");
  const [accounts,setAccounts]   = useState([]);
  const [countries,setCountries] = useState(BASE_COUNTRIES);
  const [cats,setCats]           = useState(BASE_CATS);
  const [loading,setLoading]     = useState(true);
  const [syncing,setSyncing]     = useState(false);
  const [notionOk,setNotionOk]   = useState(false);
  const [editAcc,setEditAcc]     = useState(null);
  const [userInfo,setUserInfo]   = useState({loading:true,ip:"",flag:"",country:"",city:""});
  const [aiProviders,setAiProviders] = useState([{id:"anthropic",key:""},{id:"openai",key:""},{id:"gemini",key:""}]);
  const [activeAIId,setActiveAIId]   = useState("anthropic");

  useEffect(()=>{ injectFonts(); },[]);

  useEffect(()=>{
    const c=lsGet(SK_CFG);
    if(c){
      if(c.dark!==undefined)setDark(c.dark);
      if(c.countries)setCountries(c.countries);
      if(c.cats)setCats(c.cats);
      if(c.aiProviders)setAiProviders(c.aiProviders);
      if(c.activeAIId)setActiveAIId(c.activeAIId);
    }
  },[]);

  useEffect(()=>{ lsSet(SK_CFG,{dark,countries,cats,aiProviders,activeAIId}); },[dark,countries,cats,aiProviders,activeAIId]);

  useEffect(()=>{
    fetch("https://ipapi.co/json/").then(r=>r.json()).then(d=>{
      const code=d.country_code||"";
      const flag=code?String.fromCodePoint(...[...code.toUpperCase()].map(c=>c.charCodeAt(0)+127397)):"🌎";
      setUserInfo({loading:false,ip:d.ip||"",flag,country:d.country_name||"",city:d.city||""});
    }).catch(()=>setUserInfo({loading:false,ip:"—",flag:"🌎",country:"",city:""}));
  },[]);

  const loadFromNotion = useCallback(async()=>{
    setSyncing(true);
    try{
      const data=await notionFetch(`/databases/${NOTION_DB_ID}/query`,"POST",{sorts:[{timestamp:"created_time",direction:"descending"}],page_size:100});
      const imgs=lsGet(SK_IMGS)||{};
      setAccounts(data.results.map(p=>{const a=notionToAcc(p);a.image=imgs[a.id]||null;return a;}));
      setNotionOk(true);
    }catch(e){console.error(e);setNotionOk(false);}
    finally{setSyncing(false);setLoading(false);}
  },[]);

  useEffect(()=>{ loadFromNotion(); },[]);

  const saveImg=(id,img)=>{if(!id||!img)return;const m=lsGet(SK_IMGS)||{};m[id]=img;lsSet(SK_IMGS,m);};

  const addAcc=async form=>{
    setSyncing(true);
    try{const r=await notionFetch("/pages","POST",{parent:{database_id:NOTION_DB_ID},properties:accToNotion({...form,createdAt:new Date().toISOString()})});const a={...notionToAcc(r),image:form.image};if(form.image)saveImg(r.id,form.image);setAccounts(prev=>[a,...prev]);}
    catch(e){console.error(e);}finally{setSyncing(false);}
  };

  const editDone=async form=>{
    setSyncing(true);
    try{await notionFetch(`/pages/${form.id}`,"PATCH",{properties:accToNotion(form)});if(form.image)saveImg(form.id,form.image);setAccounts(prev=>prev.map(a=>a.id===form.id?{...form}:a));}
    catch(e){console.error(e);}finally{setSyncing(false);setEditAcc(null);setView("inventory");}
  };

  const changeStatus=async(id,status,realPrice)=>{
    const acc=accounts.find(a=>a.id===id);if(!acc)return;
    const now=new Date().toISOString();
    const u={...acc,status,realSellPrice:status==="sold"?realPrice:acc.realSellPrice,soldAt:status==="sold"?now:acc.soldAt,disqAt:status==="disqualified"?now:acc.disqAt,profit:status==="sold"?(realPrice||0)-(parseFloat(acc.buyPrice)||0):status==="available"?null:acc.profit};
    setAccounts(prev=>prev.map(a=>a.id===id?u:a));
    setSyncing(true);try{await notionFetch(`/pages/${id}`,"PATCH",{properties:accToNotion(u)});}catch(e){console.error(e);}finally{setSyncing(false);}
  };

  const soldToDisq=async id=>{
    const acc=accounts.find(a=>a.id===id);if(!acc)return;
    const u={...acc,status:"disqualified",disqAt:new Date().toISOString(),profit:null,realSellPrice:null,soldAt:null};
    setAccounts(prev=>prev.map(a=>a.id===id?u:a));
    setSyncing(true);try{await notionFetch(`/pages/${id}`,"PATCH",{properties:accToNotion(u)});}catch(e){console.error(e);}finally{setSyncing(false);}
  };

  const delAcc=async id=>{
    setAccounts(prev=>prev.filter(a=>a.id!==id));
    setSyncing(true);try{await notionFetch(`/pages/${id}`,"PATCH",{archived:true});}catch(e){console.error(e);}finally{setSyncing(false);}
  };

  const NAV=[
    {id:"dashboard",l:"Inicio",I:I.home},
    {id:"inventory",l:"Stock",I:I.list},
    {id:"add",l:"Agregar",I:I.plus,add:true},
    {id:"reports",l:"Reportes",I:I.chart},
    {id:"settings",l:"Config",I:I.cog},
  ];

  if(loading)return(
    <div style={{height:"100dvh",background:"#09090E",display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:14}}>
      <div style={{background:"#0A0A0A",borderRadius:16,padding:"16px 20px"}}>
        <img src={LOGO_FULL} style={{width:220,height:"auto",objectFit:"contain",animation:"fadeIn .6s ease"}} alt="Cimaron"/>
      </div>
      <div style={{fontSize:11,color:"#333",fontFamily:"system-ui",animation:"pulse 1.5s infinite",fontWeight:600,letterSpacing:.5}}>CONECTANDO CON NOTION...</div>
    </div>
  );

  return <>
    <style>{mkCSS(dark)}</style>
    <div className="app">
      {view==="dashboard" && <Dashboard accounts={accounts} syncing={syncing} userInfo={userInfo} dark={dark} goto={v=>{setEditAcc(null);setView(v);}}/>}
      {view==="inventory" && <Inventory accounts={accounts} countries={countries} syncing={syncing} dark={dark} onStatusChange={changeStatus} onDelete={delAcc} onEdit={acc=>{setEditAcc(acc);setView("add");}} onSoldToDisq={soldToDisq}/>}
      {view==="add"       && <AddEdit onSave={editAcc?editDone:addAcc} onCancel={()=>{setEditAcc(null);setView("inventory");}} countries={countries} cats={cats} editAcc={editAcc} syncing={syncing} aiProviders={aiProviders} activeAIId={activeAIId}/>}
      {view==="reports"   && <Reportes accounts={accounts}/>}
      {view==="settings"  && <Ajustes dark={dark} setDark={setDark} countries={countries} setCountries={setCountries} cats={cats} setCats={setCats} notionOk={notionOk} aiProviders={aiProviders} setAiProviders={setAiProviders} activeAIId={activeAIId} setActiveAIId={setActiveAIId}/>}
      <nav className="bnav">
        {NAV.map(({id,l,I:Icon,add})=>(
          <button key={id} className={"nb "+(view===id?"on":"")+(add?" add-btn":"")} onClick={()=>{if(id==="add")setEditAcc(null);setView(id);}}>
            <div className="ni"><Icon width={add?20:18} height={add?20:18}/></div>
            <span className="nl">{l}</span>
          </button>
        ))}
      </nav>
    </div>
  </>;
}
